package tooltips.runtime;

/*Generated by MPS */

import javax.swing.Timer;
import java.awt.event.ActionListener;
import java.awt.event.ActionEvent;
import org.jetbrains.annotations.NotNull;

public abstract class TooltipTimer {
  public abstract void showCurrentTooltip(boolean immediately);

  private Timer delayBeforeShowTimer;
  private Timer showImmediatelyTimer;
  private boolean showImmediately;

  public TooltipTimer() {
    delayBeforeShowTimer = new Timer(0, new ActionListener() {
      public void actionPerformed(ActionEvent ignored) {
        showCurrentTooltip(false);
        showImmediately = true;
      }
    });
    delayBeforeShowTimer.setRepeats(false);

    showImmediatelyTimer = new Timer(0, new ActionListener() {
      public void actionPerformed(ActionEvent ignored) {
        showImmediately = false;
      }
    });
    showImmediatelyTimer.setRepeats(false);
  }

  public void mouseMovedIn(@NotNull final TooltipTimingProperties timing, boolean isCtrlDown, boolean hasPlatformTooltip) {
    showImmediatelyTimer.stop();
    if (isCtrlDown) {
      showImmediately = true;
    }
    if (hasPlatformTooltip) {
      showImmediately = false;
    }
    if (showImmediately) {
      showCurrentTooltip(true);
    } else {
      delayBeforeShowTimer.setInitialDelay((hasPlatformTooltip ? timing.getLongDelayBeforeShow() : timing.getShortDelayBeforeShow()));
      delayBeforeShowTimer.start();
    }
  }

  public void mouseMovedOut(@NotNull final TooltipTimingProperties timing) {
    delayBeforeShowTimer.stop();
    showImmediatelyTimer.setInitialDelay(timing.getShowImmediatelyPeriod());
    showImmediatelyTimer.start();
  }
}
